// useProductData.ts ‚Äî logic only
export const useProductData = (id: string) => {
  const product = useSignal<Product | null>(null);
  const error = useSignal<string | null>(null);

  useTask$(async ({ track }) => {
    track(() => id);
    try {
      product.value = await fetchProduct(id);
    } catch (e) {
      error.value = 'Failed to load';
    }
  });

  return { product, error };
};

// ProductCard.tsx ‚Äî presentation only
export const ProductCard = component$<{ id: string }>(({ id }) => {
  const { product, error } = useProductData(id);
  if (error.value) return <p>{error.value}</p>;
  return <div class="card">{product.value?.name ?? 'Loading‚Ä¶'}</div>;
});

import { component$, createContextId, useContext, useContextProvider, useSignal, useStore, type Signal } from '@builder.io/qwik';

const UserCtx = createContextId<{ name: string }>('user');

export const Root = component$(() => {
  const user = useStore({ name: 'Ada' });    // context store ‚Äî shared sub-tree
  useContextProvider(UserCtx, user);
  const count = useSignal(0);                // local signal ‚Äî only Root reads it
  return <Child count={count} />;           // lift signal ref as prop
});

export const Child = component$<{ count: Signal<number> }>(({ count }) => {
  const user = useContext(UserCtx);          // context consumer, no prop drilling
  return <button onClick$={() => count.value++}>{user.name}: {count.value}</button>;
});

import { component$, useSignal, useComputed$ } from '@builder.io/qwik';

export const Cart = component$(() => {
  const price = useSignal(49.99);
  const quantity = useSignal(2);
  const coupon = useSignal(0.1);

  // ‚úÖ Auto-tracks all three signals, recomputes only when they change
  const total = useComputed$(
    () => price.value * quantity.value * (1 - coupon.value)
  );

  // ‚ùå Overkill ‚Äî just use price.value directly in JSX
  // const label = useComputed$(() => `$${price.value}`);

  return <p>Total: ${total.value.toFixed(2)}</p>;
});

import { component$, useSignal } from '@builder.io/qwik';
