// Server state: serialized at SSR, never re-runs on client
export const useUser = routeLoader$(async ({ params }) => {
  return fetchUser(params.id);
});

export default component$(() => {
  const user = useUser(); // already resolved ‚Äî zero client waterfall

  const query = useSignal('');
  const results = useResource$(async ({ track, cleanup }) => {
    track(() => query.value);          // re-fetch when query changes
    const ctrl = new AbortController();
    cleanup(() => ctrl.abort());       // cancel stale requests
    return search(query.value, { signal: ctrl.signal });
  });

  return (
    <>
      <p>User: {user.value.name}</p>
      <input bind:value={query} />
      <Resource value={results} onResolved={(r) => <Results data={r} />} />
    </>
  );
});

