import { component$, useResource$, Resource } from '@builder.io/qwik';
import { routeLoader$ } from '@builder.io/qwik-city';

export const usePosts = routeLoader$(async ({ fail }) => {
  const res = await fetch('https://api.example.com/posts');
  if (!res.ok) throw fail(res.status, { message: 'Feed unavailable' });
  return res.json() as Promise<Post[]>;
});

export default component$(() => {
  const postsSignal = usePosts();
  return (
    <Resource
      value={postsSignal}
      onPending={() => <p>Loading feed‚Ä¶</p>}
      onRejected={(err) => <p class="text-red-500">{err.message}</p>}
      onResolved={(posts) =>
        posts.length === 0
          ? <p>No posts yet.</p>
          : <ul>{posts.map(p => <li key={p.id}>{p.title}</li>)}</ul>
      }
    />
  );
});

