// routeLoader$ ‚Üí SSR'd content, LCP element has zero JS dependency
export const useArticles = routeLoader$(async () =>
  fetch('/api/articles').then(r => r.json())
);

export const Feed = component$(() => {
  const articles = useArticles();       // SSR-rendered, LCP-safe
  const open = useSignal(false);        // surgical signal update, no tree re-render

  useVisibleTask$(async () => {
    // strategy: 'intersection-observer' (default) ‚Äî deferred until visible
    await import('./analytics').then(m => m.track('feed-view'));
  });

  return (
    <section style={{ minHeight: '480px' }}>  {/* reserve space ‚Üí no CLS */}
      {articles.value.map(a => <article key={a.id}>{a.title}</article>)}
      {/* onClick$ is lazy-loaded on first click ‚Üí low INP, no upfront JS cost */}
      <button onClick$={() => (open.value = !open.value)}>More</button>
    </section>
  );
});

import { component$, useVisibleTask$ } from '@builder.io/qwik';

export default component$(() => {
  useVisibleTask$(({ cleanup }) => {
    const controller = new AbortController();
    const handler = (e: Event) => console.log('scrolled', e);

    window.addEventListener('scroll', handler);
    fetch('/api/feed', { signal: controller.signal });

    cleanup(() => {
      window.removeEventListener('scroll', handler);
      controller.abort();
    });
  });

  return <div>Feed</div>;
});

// ws.ts
let ws: WebSocket | null = null;
export const getWS = (url: string) => {
  if (!ws || ws.readyState > 1) ws = new WebSocket(url);
  return ws;
};

// ChatComponent.tsx
export default component$(() => {
  const messages = useSignal<string[]>([]);
  const draft = useSignal('');

  useVisibleTask$(({ cleanup }) => {
    const socket = getWS('wss://api.example.com/ws');
    socket.onmessage = (e) => (messages.value = [...messages.value, e.data]);
    cleanup(() => socket.close());
  });

  const send = $(() => {
    messages.value = [...messages.value, draft.value]; // optimistic
    getWS('wss://api.example.com/ws').send(JSON.stringify({ text: draft.value }));
    draft.value = '';
  });

  return <button onClick$={send}>Send</button>;
});

