import { server$ } from '@builder.io/qwik-city';

const BASE = import.meta.env.VITE_API_URL;

async function apiFetch(path: string, init?: RequestInit, retries = 2): Promise<unknown> {
  const res = await fetch(`${BASE}${path}`, { 'Content-Type': 'application/json', ...init });
  if (res.status === 429 && retries > 0) {
    await new Promise(r => setTimeout(r, 500));
    return apiFetch(path, init, retries - 1);
  }
  if (!res.ok) throw new Error(`${res.status} ${path}`);
  return res.json();
}

export const apiGet = server$(async function (path: string) {
  const token = this.cookie.get('auth')?.value;
  return apiFetch(path, { headers: { Authorization: `Bearer ${token}` } });
});

import { component$, useSignal, useVisibleTask$ } from '@builder.io/qwik';
import { animate } from '@motionone/dom';

export default component$(() => {
  const cardRef = useSignal<Element>();
  const visible = useSignal(false);

  useVisibleTask$(({ track }) => {
    track(() => visible.value);
    const reduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
    if (reduced || !cardRef.value) return;
    animate(
      cardRef.value,
      { opacity: visible.value ? [0, 1] : [1, 0], y: visible.value ? [-12, 0] : [0, -12] },
      { duration: 0.25, easing: 'ease-out' }
    );
  });

  return (
    <>
      <button onClick$={() => (visible.value = !visible.value)}>Toggle</button>
      <div ref={cardRef} class={visible.value ? 'block' : 'hidden'}>Card</div>
    </>
  );
});

