});

// hooks/use-toast.ts ‚Äî consume anywhere in the tree
export const useToast = () => {
  const ctx = useContext(ToastCtx);
  return {
    add: $((msg: string, type: 'info' | 'error' = 'info') =>
      ctx.items.push({ id: Date.now(), msg, type })),
    dismiss: $((id: number) => {
      ctx.items = ctx.items.filter(t => t.id !== id);
    }),
  };
};

