import { component$, useVisibleTask$ } from '@builder.io/qwik';
import * as Sentry from '@sentry/qwik';
import { onLCP, onCLS } from 'web-vitals';

export default component$(() => {
  useVisibleTask$(() => {
    Sentry.init({
      dsn: import.meta.env.PUBLIC_SENTRY_DSN,
      tracesSampleRate: 0.1,
      integrations: [Sentry.browserTracingIntegration()],
    });
    onLCP(m => Sentry.getCurrentScope().setMeasurement('lcp', m.value, 'millisecond'));
    onCLS(m => Sentry.getCurrentScope().setMeasurement('cls', m.value, ''));
  });
  return <></>;  // wrap around QwikCityProvider in real usage
});

import { component$, useSignal, useComputed$ } from '@builder.io/qwik';

export default component$(() => {
  const count = useSignal(0);
  const doubled = useComputed$(() => count.value * 2);

  // Only the <span> nodes re-evaluate on signal change.
  // This component function never re-runs after initial render.
  return (
    <div>
      <button onClick$={() => count.value++}>Increment</button>
      <span>{count.value}</span>
      <span>{doubled.value}</span>
    </div>
  );
});
